// Structure to hold the results 
#[derive(Default)]
#[derive(Debug)]
pub struct Atom {
    atom_id: usize,
    atom_symbol: String,
    is_aromatic: bool,
    is_in_bracket: bool, 
    has_hs: bool, 
    isotopic_number: u8,
    chirality: String,
    n_hs: u8,
    charge: i8,
    class: String
}
#[derive(Default)]
#[derive(Debug)]
pub struct Bond {
    bond_id: usize,
    atom_one: usize,
    atom_two: usize,
    bond_symbol: String
}
#[derive(Default)]
#[derive(Debug)]
pub struct Symbol {
    symbol: String
}
#[derive(Default)]
#[derive(Debug)]
pub struct Structure {
    atoms:        Vec<Atom>,
    bonds:        Vec<Bond>,
    symbols:      Vec<Symbol>,
    input_smiles: String,
    status:       bool,
    error:        String
}

