// Function to get chunk
pub fn get_chunk(getc_smiles_string: &String, getc_start_pos: usize, getc_length: usize) -> &str {
  let getc_result: &str = &getc_smiles_string[getc_start_pos..cmp::min((getc_start_pos + getc_length), (getc_smiles_string.len()))];
  return getc_result;
}

// Function to get the longest possible symbol from the current SMILES chunk
pub fn get_symbol(getls_smiles_chunk: &str, s_one: &[&str], s_two: &[&str],
                            s_three: &[&str], s_four: &[&str], s_five: &[&str]) -> String {
  // Evaluate chunk length
  let chunk_length: usize = getls_smiles_chunk.len();
  // Throw an error if chunk is longer than 5 characters
  if chunk_length > 5 {
      let symb_error = format!("Chunk is longer than 5 characters, smth is wrong: {}", getls_smiles_chunk);
      return symb_error;
  }
  if SYMBOLFIVE.contains(&&getls_smiles_chunk[0..cmp::min(5,getls_smiles_chunk.len())]) {
      return getls_smiles_chunk[0..cmp::min(5,getls_smiles_chunk.len())].to_string();
  }
  if SYMBOLFOUR.contains(&&getls_smiles_chunk[0..cmp::min(4,getls_smiles_chunk.len())]) {
      return getls_smiles_chunk[0..cmp::min(4,getls_smiles_chunk.len())].to_string();
  }
  if SYMBOLTHREE.contains(&&getls_smiles_chunk[0..cmp::min(3,getls_smiles_chunk.len())]) {
      return getls_smiles_chunk[0..cmp::min(3,getls_smiles_chunk.len())].to_string();
  }
  if SYMBOLTWO.contains(&&getls_smiles_chunk[0..cmp::min(2,getls_smiles_chunk.len())]) {
      return getls_smiles_chunk[0..cmp::min(2,getls_smiles_chunk.len())].to_string();
  }
  if SYMBOLONE.contains(&&getls_smiles_chunk[0..cmp::min(1,getls_smiles_chunk.len())]) {
      return getls_smiles_chunk[0..cmp::min(1,getls_smiles_chunk.len())].to_string();
  } else {
      let symb_error = format!("unknown symbol in chunk: {}", getls_smiles_chunk);
      return symb_error;
  }
}

// Function to update structure
pub fn update_structure(mut us_structure: Structure, us_symbol: &String, us_prev_symbol: String,
                        us_simple_ct_on: u8, us_bracket: u8, us_last_symbol: u8) -> Structure {
  // Function to insert the symbol
  fn insert_symbol(mut ins_structure: Structure, ins_symbol: &String, ins_prev_symbol: String,
                          ins_simple_ct_on: u8, ins_bracket: u8, ins_last_symbol: u8) -> Structure {
    // Case - for the first symbol
    if ins_prev_symbol == "" {
        // Decide on the symbol class
        // Case atom
        if SYMBS_ATOM.contains(&ins_symbol.as_str()) {
          unimplemented!();
        }
        // Case open square bracket
        if ins_symbol == &"[".to_string() {
          unimplemented!();
        }
        // Case open parentheses
        if ins_symbol == &"(".to_string() {
          unimplemented!();
        }
    } else if ins_last_symbol == 1 {
        // Decide on the symbol class
        // Case atom
        if SYMBS_ATOM.contains(&ins_symbol.as_str()) {
          unimplemented!();
        }
        // Case close square brackets
        if ins_symbol == &"]".to_string() {
          unimplemented!();
        }
        // Case close parentheses
        if ins_symbol == &")".to_string() {
          unimplemented!();
        }
        // Case close ring
        if SYMBS_BMRING.contains(&ins_symbol.as_str()) {
          unimplemented!();
        }
    } else {
        // Case - for the intermediate symbol
        // Case - atom
        if SYMBS_ATOM.contains(&ins_symbol.as_str()) {
          unimplemented!();
        }
        // Case - ring
        if SYMBS_BMRING.contains(&ins_symbol.as_str()) {
          unimplemented!();
        }
        // Case - bond modifier and not ring
        if SYMBS_BM.contains(&ins_symbol.as_str()) {
          unimplemented!();
        }
        // Case open square bracket
        if ins_symbol == &"[".to_string() {
          unimplemented!();
        }
        // Case close square bracket
        if ins_symbol == &"]".to_string() {
          unimplemented!();
        }
        // Case open parentheses
        if ins_symbol == &"(".to_string() {
          unimplemented!();
        }
        // Case close parentheses
        if ins_symbol == &")".to_string() {
          unimplemented!();
        }
        // Case cis / trans
        if ins_symbol == &"/".to_string() || ins_symbol == &"\\".to_string() {
          unimplemented!();
        }
    }
    //return ins_structure;
    unimplemented!();
  }
  // Case when this symbol is the first symbol
  if us_prev_symbol == "" {
    // check if current symbol is viable
    if SYMBS_ALLOWED_START.contains(&&us_symbol[0..us_symbol.len()]) {
        // Actually update latter
        us_structure = insert_symbol(us_structure, us_symbol, us_prev_symbol,
                                  us_simple_ct_on, us_bracket, us_last_symbol);
        return us_structure;
    } else {
        us_structure.status = false;
        us_structure.error = String::from("unacceptable first symbol in SMILES string");
        return us_structure;
    }
  } else if us_last_symbol == 1 {
    // check if the last symbol is viable
    if SYMBS_ALLOWED_END.contains(&&us_symbol[0..us_symbol.len()]) {
        // Actually update latter
        return us_structure;
    } else {
        us_structure.status = false;
        us_structure.error = String::from("unacceptable last symbol in SMILES string");
        return us_structure;
    }
  } else {
          return us_structure;
  }
}

// Function to parse SMILES
pub fn parse_smiles(ps_smiles_string: &String, mut ps_structure: Structure) -> Structure {
  // Initial state
  ps_structure.status = true;
  let ps_n_all: usize = ps_smiles_string.len();
  let mut ps_position: usize = 0;
  let mut ps_chunk: &str = "";
  let mut ps_symbol: String = String::from("");
  let mut ps_simple_ct_on: u8 = 0;
  let mut ps_open_bracket: u8 = 0;
  let mut ps_last_symbol:  u8 = 0;
  let mut ps_next_position: usize = 0;
  let mut ps_prev_symbol: String = "".to_string();

  // Parse SMILES in a loop, v1 chunk it
  while ps_n_all > ps_position {
      // Get this chunk
      ps_chunk = get_chunk(ps_smiles_string, ps_position, 5);
      // Test
      //println!("{:?}", ps_chunk);

      // Get this symbol
      ps_symbol = get_symbol(ps_chunk, &SYMBOLONE, &SYMBOLTWO, &SYMBOLTHREE, &SYMBOLFOUR, &SYMBOLFIVE);

      // Update position according to the symbol length
      ps_position = (ps_position + 5) - (5 - ps_symbol.len());

      // Update state
      if ps_position >= ps_n_all {
          ps_last_symbol = 1;
      } 

      // Update structure
      ps_structure = update_structure(ps_structure, &ps_symbol, ps_prev_symbol,
                                      ps_simple_ct_on, ps_open_bracket, ps_last_symbol);

      // Check updated structure
      if ps_structure.status == false {
          return ps_structure;
      }

      // Finally, update the previous symbol
      ps_prev_symbol = ps_symbol.clone();
  }

  // Output
  return ps_structure;
}